import { Helmet } from "react-helmet-async";

const DEFAULT_TITLE = "Castia Market Insight";
const DEFAULT_DESC = "Real-time analytics, pricing history, and seller reputation for the Castia economy.";
const DEFAULT_URL = "https://lektodesigns.github.io/castia-market-insight";
const DEFAULT_IMAGE = "https://lektodesigns.github.io/castia-market-insight/icon.png";
const THEME_COLOR = "#10b981"; // Emerald-500

/**
 * SEO Component for managing dynamic Open Graph and Discord meta tags.
 * 
 * @param {Object} props
 * @param {string} props.title - Page title suffix
 * @param {string} props.description - Meta description
 * @param {string} props.image - OG image URL (must be absolute)
 * @param {string} props.url - Canonical URL
 * @param {string} props.type - OG type (default: website)
 */
export default function SEO({ 
  title, 
  description = DEFAULT_DESC, 
  image = DEFAULT_IMAGE, 
  url = DEFAULT_URL,
  type = "website" 
}) {
  const fullTitle = title ? `${title} | ${DEFAULT_TITLE}` : DEFAULT_TITLE;

  return (
    <Helmet>
      {/* Standard Meta Tags */}
      <title>{fullTitle}</title>
      <meta name="description" content={description} />
      <meta name="theme-color" content={THEME_COLOR} />

      {/* Open Graph / Facebook */}
      <meta property="og:type" content={type} />
      <meta property="og:url" content={url} />
      <meta property="og:title" content={fullTitle} />
      <meta property="og:description" content={description} />
      <meta property="og:image" content={image} />
      <meta property="og:image:secure_url" content={image} />
      <meta property="og:image:type" content="image/png" />
      <meta property="og:image:width" content="1600" />
      <meta property="og:image:height" content="1600" />
      <meta property="og:site_name" content={DEFAULT_TITLE} />

      {/* Twitter */}
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:url" content={url} />
      <meta name="twitter:title" content={fullTitle} />
      <meta name="twitter:description" content={description} />
      <meta name="twitter:image" content={image} />
    </Helmet>
  );
}
