import { useMemo } from "react";
import { useParams, useSearchParams, useLocation } from "react-router-dom";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import SEO from "@/components/ui/SEO";
import { Reveal } from "@/components/landing/motion";
import ItemDetailContent from "@/components/landing/ItemDetailContent";
import { useMarket } from "@/lib/MarketContext";
import { fmt } from "@/lib/parseItem";

const BASE_URL = "https://lektodesigns.github.io/castia-market-insight";

export default function ItemDetail() {
  const { key: rawKey } = useParams();
  const [searchParams, setSearchParams] = useSearchParams();
  const location = useLocation();
  const { market } = useMarket();

  const itemKey = useMemo(() => {
    try { return decodeURIComponent(rawKey || ""); } catch { return rawKey || ""; }
  }, [rawKey]);

  const item = useMemo(() => {
    if (!market?.rows?.length || !itemKey) return null;
    const idx = market.rowsByKey;
    // Try exact match first
    if (idx.has(itemKey)) return idx.get(itemKey);
    // Case-insensitive fallback: find by lowercase key
    const lowerKey = itemKey.toLowerCase();
    for (const [k, row] of idx.entries()) {
      if (k.toLowerCase() === lowerKey) return row;
    }
    return null;
  }, [market, itemKey]);

  const openSeller = (name) => {
    const next = new URLSearchParams(searchParams);
    next.set("sellerView", name);
    setSearchParams(next);
  };

  const itemDesc = useMemo(() => {
    if (!item) return null;
    const name = item.name || itemKey;
    const median = item.median ? fmt(item.median) : null;
    return `View ${name} prices on Castia Market — ${median ? `median ${median}` : "real-time pricing"}${item.confidence ? `, ${item.confidence} confidence` : ""}.`;
  }, [item, itemKey]);

  const itemUrl = useMemo(() => {
    return `${BASE_URL}${location.pathname}${location.search}`;
  }, [location.pathname, location.search]);

  return (
    <div data-testid="item-detail-page" className="min-h-screen bg-bg-base text-white font-body">
      <SEO 
        title={item?.name || itemKey} 
        description={itemDesc || undefined} 
        url={itemUrl}
      />
      <Header />
      <main className="pt-24 pb-16">
        <Reveal className="max-w-4xl mx-auto px-6 md:px-12">
          <ItemDetailContent itemKey={itemKey} onOpenSeller={openSeller} />
        </Reveal>
      </main>
      <Footer />
    </div>
  );
}
